const response   = $input.first().json;
const data       = response.result || response;
const inputUrl   = $('Read Profile URLs from Sheet').first().json.linkedin_url;

if (!data || !data.name || response.status === 'error') {
  return [{ json: {
    input_url: inputUrl, name: 'Not found',
    job_title: '', company: '', headline: '', location: '',
    country: '', industry: '', email: '', mobile: '', website: '',
    connections: '', followers: '', is_employed: '',
    is_job_seeker: '', years_experience: '', linkedin_url: ''
  }}];
}

const currentYear = new Date().getFullYear();
const firstYear   = parseInt(data.firstRoleYear || data.first_role_year || 0);

return [{ json: {
  input_url:       inputUrl,
  name:            data.name              || '',
  job_title:       data.jobTitle          || data.job_title       || '',
  company:         data.company           || '',
  headline:        data.headline          || '',
  location:        data.location          || '',
  country:         data.country           || '',
  industry:        data.industry          || '',
  email:           data.email             || '',
  mobile:          data.mobileNumber      || data.mobile          || '',
  website:         data.website           || '',
  connections:     data.connections       || '',
  followers:       data.followers         || '',
  is_employed:     data.isCurrentlyEmployed !== undefined ? String(data.isCurrentlyEmployed) : '',
  is_job_seeker:   data.isJobSeeker        !== undefined ? String(data.isJobSeeker)        : '',
  years_experience:firstYear ? String(currentYear - firstYear) : '',
  linkedin_url:    data.linkedinUrl       || data.linkedin_url    || inputUrl
}}];
